namespace sv_27a74bb34d1f4463a1c9a7ab5dec8e0e.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public sealed record ShipmentDetails(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> Updates);

public sealed record StatusUpdate(
    DateTimeOffset Timestamp,
    string Description,
    string Location);

using sv_27a74bb34d1f4463a1c9a7ab5dec8e0e.Client.Services;

namespace sv_27a74bb34d1f4463a1c9a7ab5dec8e0e.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 23, 8, 0, 0, TimeSpan.Zero), "Package picked up", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility", "Philadelphia, PA"),
                new(new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.Zero), "In transit to destination", "Chicago, IL"),
            }),

        ["TRK-002"] = new ShipmentDetails(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), "Package picked up", "Seattle, WA"),
                new(new DateTimeOffset(2026, 5, 21, 11, 0, 0, TimeSpan.Zero), "Out for delivery", "San Francisco, CA"),
                new(new DateTimeOffset(2026, 5, 21, 14, 45, 0, TimeSpan.Zero), "Delivered - Left at front door", "San Francisco, CA"),
            }),

        ["TRK-003"] = new ShipmentDetails(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.Zero), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_27a74bb34d1f4463a1c9a7ab5dec8e0e.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>

        <dt>Location</dt>
        <dd>@_shipment.Location</dd>

        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    @if (_shipment.Updates.Count == 0)
    {
        <p>No updates yet.</p>
    }
    else
    {
        <ul>
            @foreach (var update in _shipment.Updates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> &mdash;
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;
    private string? _lastLoadedTrackingNumber;

    protected override async Task OnParametersSetAsync()
    {
        // If the tracking number hasn't changed, don't reload
        if (string.Equals(_lastLoadedTrackingNumber, TrackingNumber, StringComparison.OrdinalIgnoreCase)
            && _shipment is not null)
        {
            return;
        }

        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();

        var ct = _cts.Token;

        _lastLoadedTrackingNumber = TrackingNumber;
        _shipment = null;
        _errorMessage = null;
        _loading = true;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — silently stop
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task RetryLoad()
    {
        _lastLoadedTrackingNumber = null;
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

