using sv_27a74bb34d1f4463a1c9a7ab5dec8e0e.Client.Services;

namespace sv_27a74bb34d1f4463a1c9a7ab5dec8e0e.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 23, 8, 0, 0, TimeSpan.Zero), "Package picked up", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility", "Philadelphia, PA"),
                new(new DateTimeOffset(2026, 5, 25, 6, 15, 0, TimeSpan.Zero), "In transit to destination", "Chicago, IL"),
            }),

        ["TRK-002"] = new ShipmentDetails(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero), "Package picked up", "Seattle, WA"),
                new(new DateTimeOffset(2026, 5, 21, 11, 0, 0, TimeSpan.Zero), "Out for delivery", "San Francisco, CA"),
                new(new DateTimeOffset(2026, 5, 21, 14, 45, 0, TimeSpan.Zero), "Delivered - Left at front door", "San Francisco, CA"),
            }),

        ["TRK-003"] = new ShipmentDetails(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            Updates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.Zero), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

